<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Expense Tracker</title>
    <style>
        body { font-family: sans-serif; max-width: 800px; margin: 20px auto; padding: 0 20px; line-height: 1.5; }
        section { border: 1px solid #ccc; padding: 15px; margin-bottom: 20px; border-radius: 8px; }
        h2 { margin-top: 0; }
        .form-group { margin-bottom: 10px; }
        label { display: block; font-weight: bold; }
        input, select { padding: 5px; width: 100%; box-sizing: border-box; }
        #form-error { color: red; font-weight: bold; margin-bottom: 10px; min-height: 1.2em; }
        .filters { display: flex; gap: 15px; flex-wrap: wrap; background: #f9f9f9; padding: 10px; border-radius: 4px; }
        .filter-item { flex: 1; min-width: 150px; }
        .summary-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(120px, 1fr)); gap: 10px; margin-bottom: 15px; }
        .cat-total { background: #eee; padding: 8px; border-radius: 4px; font-size: 0.9em; border: 1px solid #ddd; }
        .expense-list { width: 100%; border-collapse: collapse; margin-top: 10px; }
        .expense { border-bottom: 1px solid #eee; }
        .expense td, .expense th { padding: 8px; text-align: left; }
        .exp-del { color: red; cursor: pointer; background: none; border: 1px solid red; border-radius: 3px; }
        .total-display { font-size: 1.2em; font-weight: bold; text-align: right; margin-top: 10px; }
    </style>
</head>
<body>

    <h1>Expense Tracker</h1>

    <section>
        <h2>Add Expense</h2>
        <div id="form-error"></div>
        <div class="form-group">
            <label for="amount">Amount</label>
            <input type="number" id="amount" step="0.01" placeholder="0.00">
        </div>
        <div class="form-group">
            <label for="category">Category</label>
            <select id="category">
                <option value="groceries">Groceries</option>
                <option value="transport">Transport</option>
                <option value="bills">Bills</option>
                <option value="fun">Fun</option>
            </select>
        </div>
        <div class="form-group">
            <label for="date">Date</label>
            <input type="date" id="date">
        </div>
        <div class="form-group">
            <label for="note">Note (Optional)</label>
            <input type="text" id="note">
        </div>
        <button id="add-expense">Add Expense</button>
    </section>

    <section>
        <h2>Filters & Summary</h2>
        <div class="filters">
            <div class="filter-item">
                <label for="filter-category">Category Filter</label>
                <select id="filter-category">
                    <option value="all">All</option>
                    <option value="groceries">Groceries</option>
                    <option value="transport">Transport</option>
                    <option value="bills">Bills</option>
                    <option value="fun">Fun</option>
                </select>
            </div>
            <div class="filter-item">
                <label for="filter-from">From Date</label>
                <input type="date" id="filter-from">
            </div>
            <div class="filter-item">
                <label for="filter-to">To Date</label>
                <input type="date" id="filter-to">
            </div>
        </div>

        <div class="summary-grid" id="category-summaries">
            <!-- Category totals generated by JS -->
        </div>
        <div class="total-display">Total: $<span id="total">0.00</span></div>
    </section>

    <table class="expense-list">
        <thead>
            <tr>
                <th>Date</th>
                <th>Category</th>
                <th>Amount</th>
                <th>Note</th>
                <th>Action</th>
            </tr>
        </thead>
        <tbody id="expense-body"></tbody>
    </table>

    <script>
        const categories = ['groceries', 'transport', 'bills', 'fun'];
        let expenses = JSON.parse(localStorage.getItem('expenses')) || [];

        // DOM Elements
        const amountInput = document.getElementById('amount');
        const categoryInput = document.getElementById('category');
        const dateInput = document.getElementById('date');
        const noteInput = document.getElementById('note');
        const addBtn = document.getElementById('add-expense');
        const errorDiv = document.getElementById('form-error');

        const filterCat = document.getElementById('filter-category');
        const filterFrom = document.getElementById('filter-from');
        const filterTo = document.getElementById('filter-to');

        const expenseBody = document.getElementById('expense-body');
        const totalDisplay = document.getElementById('total');
        const summaryContainer = document.getElementById('category-summaries');

        // Initialize Category Summary Elements
        function initSummaryElements() {
            summaryContainer.innerHTML = '';
            categories.forEach(cat => {
                const div = document.createElement('div');
                div.className = 'cat-total';
                div.setAttribute('data-cat', cat);
                div.textContent = `${cat}: $0.00`;
                summaryContainer.appendChild(div);
            });
        }

        function save() {
            localStorage.setItem('expenses', JSON.stringify(expenses));
            render();
        }

        function addExpense() {
            const amount = parseFloat(amountInput.value);
            const category = categoryInput.value;
            const date = dateInput.value;
            const note = noteInput.value;

            if (isNaN(amount) || amount <= 0) {
                errorDiv.textContent = "Please enter a valid positive number for amount.";
                return;
            }
            if (!date) {
                errorDiv.textContent = "Please select a date.";
                return;
            }

            errorDiv.textContent = "";
            expenses.push({ id: Date.now(), amount, category, date, note });
            amountInput.value = ''; 
            noteInput.value = '';
            save();
        }

        function deleteExpense(id) {
            expenses = expenses.filter(e => e.id !== id);
            save();
        }

        function render() {
            const catFilter = filterCat.value;
            const fromDate = filterFrom.value;
            const toDate = filterTo.value;

            // Sort newest first (by date, then by ID for stability)
            const sortedExpenses = [...expenses].sort((a, b) => {
                if (b.date !== a.date) return b.date.localeCompare(a.date);
                return b.id - a.id;
            });

            expenseBody.innerHTML = '';
            let grandTotal = 0;
            const catTotals = {};
            categories.forEach(c => catTotals[c] = 0);

            sortedExpenses.forEach(exp => {
                const matchCat = (catFilter === 'all' || exp.category === catFilter);
                const matchFrom = (!fromDate || exp.date >= fromDate);
                const matchTo = (!toDate || exp.date <= toDate);

                if (matchCat && matchFrom && matchTo) {
                    // Update totals
                    grandTotal += exp.amount;
                    catTotals[exp.category] += exp.amount;

                    // Create row
                    const row = document.createElement('tr');
                    row.className = 'expense';
                    row.innerHTML = `
                        <td>${exp.date}</td>
                        <td>${exp.category}</td>
                        <td>${exp.amount.toFixed(2)}</td>
                        <td>${exp.note}</td>
                        <td><button class="exp-del" onclick="deleteExpense(${exp.id})">Delete</button></td>
                    `;
                    expenseBody.appendChild(row);
                }
            });

            // Update Summary UI
            totalDisplay.textContent = grandTotal.toFixed(2);
            categories.forEach(cat => {
                const el = document.querySelector(`.cat-total[data-cat="${cat}"]`);
                if (el) el.textContent = `${cat}: $${catTotals[cat].toFixed(2)}`;
            });
        }

        // Event Listeners
        addBtn.addEventListener('click', addExpense);
        filterCat.addEventListener('change', render);
        filterFrom.addEventListener('input', render);
        filterTo.addEventListener('input', render);

        // Init
        initSummaryElements();
        render();
    </script>
</body>
</html>
